module top_module(
	input wire clk,
	input wire reset,
	input wire enable,
	output wire out
);reg [2:0] cnt = 3'b0;
	  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt)
		if(reset)
			cnt <= 3'b0;
		else if(enable)
			cnt <= cnt + 1'b1;
	assign out = cnt[2];
endmodule
